mapper.update:
UPDATE editor_document
SET title = #{title},
    schema_version = #{schemaVersion},
    content = cast(#{content} as jsonb),
    current_version = current_version + 1,
    updated_at = now()
WHERE id = #{id}
  AND owner_id = #{ownerId}
  AND current_version = #{currentVersion}
  AND deleted_at IS NULL

UPDATE editor_document
SET title = #{title},
    updated_at = now()
WHERE id = #{id}
  AND owner_id = #{ownerId}
  AND deleted_at IS NULL

UPDATE editor_document
SET deleted_at = now()
WHERE id = #{id}
  AND owner_id = #{ownerId}
  AND deleted_at IS NULL
